        private static string ParseSelectColumns(string selectParam, HashSet<string> allowedColumns)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
            {
                // Return all allowed columns
                var allCols = new List<string>();
                foreach (var col in allowedColumns)
                {
                    allCols.Add($"[{col}]");
                }
                return string.Join(", ", allCols);
            }

            var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries);
            var validColumns = new List<string>();

            foreach (var col in requestedColumns)
            {
                var trimmed = col.Trim();
                if (allowedColumns.Contains(trimmed))
                {
                    validColumns.Add($"[{trimmed}]");
                }
                else
                {
                    throw new ArgumentException($"Column '{trimmed}' is not allowed.");
                }
            }

            if (validColumns.Count == 0)
            {
                throw new ArgumentException("No valid columns specified.");
            }

            return string.Join(", ", validColumns);
        }

        /// <summary>
        /// Parses filter parameters from query string.
        /// Format: filter_ColumnName_operator=value
        /// Examples: 
        ///   filter_Region_eq=West
        ///   filter_Amount_gte=1000
        ///   filter_Status_in=Active,Pending
        ///   filter_Name_like=%Smith%
        /// </summary>
        private static (string clause, List<SqlParameter> parameters) ParseFilters(
            IQueryCollection query, HashSet<string> allowedColumns)
        {
            var conditions = new List<string>();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            foreach (var key in query.Keys)
            {
                if (key == null || !key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                var parts = key.Split('_', 3);
                if (parts.Length != 3)
                {
                    throw new ArgumentException($"Invalid filter format: '{key}'. Expected format: filter_ColumnName_operator");
                }

                string columnName = parts[1];
                string operatorKey = parts[2];
                string value = query[key];

                // Validate column name against whitelist
                if (!allowedColumns.Contains(columnName))
                {
                    throw new ArgumentException($"Filter column '{columnName}' is not allowed.");
                }

                // Validate operator against whitelist
                if (!AllowedOperators.TryGetValue(operatorKey, out string sqlOperator))
                {
                    throw new ArgumentException($"Filter operator '{operatorKey}' is not allowed. Allowed: {string.Join(", ", AllowedOperators.Keys)}");
                }

                if (string.IsNullOrEmpty(value))
                {
                    throw new ArgumentException($"Filter value for '{columnName}' cannot be empty.");
                }

                // Handle IN operator specially
                if (operatorKey.Equals("in", StringComparison.OrdinalIgnoreCase))
                {
                    var inValues = value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                    if (inValues.Length == 0)
                    {
                        throw new ArgumentException($"IN filter for '{columnName}' requires at least one value.");
                    }

                    var inParamNames = new List<string>();
                    foreach (var inVal in inValues)
                    {
                        string paramName = $"@p{paramIndex++}";
                        inParamNames.Add(paramName);
                        parameters.Add(new SqlParameter(paramName, inVal.Trim()));
                    }

                    conditions.Add($"[{columnName}] IN ({string.Join(", ", inParamNames)})");
                }
                else
                {
                    string paramName = $"@p{paramIndex++}";

                    // For LIKE operator, the value should already contain wildcards from the caller
                    // We parameterize it so it's safe
                    conditions.Add($"[{columnName}] {sqlOperator} {paramName}");
                    parameters.Add(new SqlParameter(paramName, value));
                }
            }

            string clause = conditions.Count > 0 ? string.Join(" AND ", conditions) : null;
            return (clause, parameters);
        }

        private static string ParseOrderBy(string orderByParam, HashSet<string> allowedColumns)
        {
            if (string.IsNullOrWhiteSpace(orderByParam))
                return null;

            var orderParts = orderByParam.Split(',', StringSplitOptions.RemoveEmptyEntries);
            var orderClauses = new List<string>();

            foreach (var part in orderParts)
            {
                var tokens = part.Trim().Split(' ', StringSplitOptions.RemoveEmptyEntries);
                if (tokens.Length == 0 || tokens.Length > 2)
                {
                    throw new ArgumentException($"Invalid order by format: '{part}'. Expected: 'ColumnName [ASC|DESC]'");
                }

                string column = tokens[0];
                string direction = tokens.Length == 2 ? tokens[1].ToUpperInvariant() : "ASC";

                if (!allowedColumns.Contains(column))
                {
                    throw new ArgumentException($"Order by column '{column}' is not allowed.");
                }

                if (!AllowedSortDirections.Contains(direction))
                {
                    throw new ArgumentException($"Sort direction '{direction}' is not valid. Use ASC or DESC.");
                }

                orderClauses.Add($"[{column}] {direction}");
            }

            return orderClauses.Count > 0 ? string.Join(", ", orderClauses) : null;
        }

        private static int ParseInt(string value, int defaultValue, int min, int max)
        {
            if (string.IsNullOrWhiteSpace(value))
                return defaultValue;

            if (!int.TryParse(value, out int result))
                return defaultValue;

            return Math.Clamp(result, min, max);
        }
